  'main calendar page  (want NO)'    : 'apps/web/src/app/[locale]/(main)/calendar/page.tsx',
};

function test(lib, libname, pat, p) {
  try {
    if (libname === 'picomatch') return lib.isMatch(p, pat);
    if (libname === 'minimatch') return lib(p, pat);
  } catch (e) { return 'ERR:' + e.message; }
}

